import{_ as d,r as a,o as p,c as m,a as e,b as o,t as i,d as t,w as h,e as l}from"./app-d223f2a5.js";const w={},f={id:"frontmatter-title-관련",tabindex:"-1"},g=e("a",{class:"header-anchor",href:"#frontmatter-title-관련","aria-hidden":"true"},"#",-1),y={class:"table-of-contents"},_=l('<hr><h2 id="project-26-part-three" tabindex="-1"><a class="header-anchor" href="#project-26-part-three" aria-hidden="true">#</a> Project 26, part three</h2><p>Seth Godin – author and marketing genius – once said “surprise and delight and connection are remarkable.” We already looked at <em>connection</em> way back in project 10, Names to Faces, where importing user photos transformed our collection view into something far more personal – and thus far more <em>important</em> to users.</p><p>The accelerometer is an almost invisibly small component in iOS devices, but I hope this project has shown you that it brings a fresh dose of delight to our apps – and that’s even after you’ve learned about many of the other frameworks iOS makes available to us.</p><p>As for “surprise”, this is somewhere we need to be a little more careful. You see, users trust us with their data: our code is running on their phone, which is packed with their lifetime of photos, emails, chats, and more – it’s a really personal device. If your app does something unexpected – if it behaves in a way they weren’t expecting – it’s easy to lose some trust, and once that trust is gone it’s really hard to win back.</p><p>However, small amounts of surprise in safe places releases a little dopamine rush, making users feel good about our app. iOS is filled with tiny things like this: the way the flashlight button on the home screen grows with pressure then clicks with a physical bump, the smooth zoom animations seen in the App Store, or even the page curl reading effect in Apple Books. None of those risk user data or make the app feel uncertain, they are just tiny touches that feel <em>great</em> every time you interact with them.</p><p>Core Motion opens up a whole area of delight for us, but make sure you use it judiciously: if everything moves your users will feel queasy, but if you add a tiny touch here and there it’s just one more thing to help bring your app to life.</p><p><strong>Today you should work through the wrap up chapter for project 26, complete its review, then work through all three of its challenges.</strong></p><h3 id="wrap-up" tabindex="-1"><a class="header-anchor" href="#wrap-up" aria-hidden="true">#</a> Wrap up</h3>',9),k={class:"hint-container details"},b=e("summary",null,"Wrap up",-1),v={href:"https://www.hackingwithswift.com/read/26/5/wrap-up",target:"_blank",rel:"noopener noreferrer"},j=e("p",null,"There's something wonderfully tactile about using the accelerometer to affect gravity in a game, because it feels incredibly realistic even though we're not using particularly good graphics.",-1),x=e("p",null,"SpriteKit is of course doing most of the hard work of collision detection, and Core Motion takes away all the complexity of working with accelerometers, so again it's our job to sew the components together to make something bigger than the sum of its parts.",-1),T=e("h4",{id:"review-what-you-learned",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#review-what-you-learned","aria-hidden":"true"},"#"),o(" Review what you learned")],-1),W=e("p",null,"Anyone can sit through a tutorial, but it takes actual work to remember what was taught. It’s my job to make sure you take as much from these tutorials as possible, so I’ve prepared a short review to help you check your learning.",-1),S={href:"https://www.hackingwithswift.com/review/hws/project-26-marble-maze",target:"_blank",rel:"noopener noreferrer"},A=l('<h4 id="challenge" tabindex="-1"><a class="header-anchor" href="#challenge" aria-hidden="true">#</a> Challenge</h4><p>One of the best ways to learn is to write your own code as often as possible, so here are three ways you should try your new knowledge to make sure you fully understand what’s going on:</p><ol><li>Rewrite the <code>loadLevel()</code> method so that it&#39;s made up of multiple smaller methods. This will make your code easier to read and easier to maintain, or at least it should do if you do a good job!</li><li>When the player finally makes it to the finish marker, nothing happens. What should happen? Well, that&#39;s down to <em>you</em> now. You could easily design several new levels and have them progress through.</li><li>Add a new block type, such as a teleport that moves the player from one teleport point to the other. Add a new letter type in <code>loadLevel()</code>, add another collision type to our enum, then see what you can do.</li></ol>',3),C={class:"hint-container info"},I=e("p",{class:"hint-container-title"},"Wrap up - Additional",-1),L={href:"https://www.hackingwithswift.com/review/hws/project-26-marble-maze",target:"_blank",rel:"noopener noreferrer"},N=e("p",null,"That’s another fun game complete, and one with lots of expansion possibilities – make sure you share your progress online!",-1),z=e("hr",null,null,-1);function B(s,Y){const n=a("router-link"),r=a("ExternalLinkIcon"),u=a("YouTube"),c=a("TagLinks");return p(),m("div",null,[e("h1",f,[g,o(" "+i(s.$frontmatter.title)+" 관련",1)]),e("blockquote",null,[e("p",null,i(s.$frontmatter.description),1)]),e("nav",y,[e("ul",null,[e("li",null,[t(n,{to:"#project-26-part-three"},{default:h(()=>[o("Project 26, part three")]),_:1}),e("ul",null,[e("li",null,[t(n,{to:"#wrap-up"},{default:h(()=>[o("Wrap up")]),_:1})])])])])]),_,e("details",k,[b,e("p",null,[e("a",v,[o("📎link"),t(r)])]),t(u,{id:"Y3RBwznf1WE"}),j,x,T,W,e("p",null,[e("a",S,[o("Click here to review what you learned in project 26."),t(r)])]),A]),e("div",C,[I,e("p",null,[e("a",L,[o("Review for Project 26: Marble Maze"),t(r)])])]),N,z,t(c)])}const M=d(w,[["render",B],["__file","87.html.vue"]]);export{M as default};
